@page "/browse/{Category}"

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<h1>@Category Recipes</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <div class="mb-4">
        <h4>Rating</h4>
        <p>⭐ @Recipe.AverageRating.ToString("F1") (@Recipe.RatingCount ratings)</p>
        <StarRating RecipeId="@Recipe.Id" />
    </div>

    <div class="mb-4">
        <h3>Ingredients</h3>
        <ul>
            @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <li>@ingredient</li>
            }
        </ul>
    </div>

    <div class="mb-4">
