toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted successfully!</strong> Thank you for sharing.
    </div>
    <a href="/" class="btn btn-primary">Back to Home</a>
}
else
{
    <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Submission.Title" />
            <ValidationMessage For="() => Submission.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Asian">Asian</option>
                <option value="American">American</option>
                <option value="French">French</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Submission.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Submission.Ingredients" />
            <ValidationMessage For="() => Submission.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="Submission.Steps" />
            <ValidationMessage For="() => Submission.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.RecipeSubmission Submission { get; set; } = new();
    private bool SubmitSuccess { get; set; }

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(Submission);
        SubmitSuccess = true;
    }
}
